// Safe HTML escape â€” bio.js loads before app.js, so we need this here.
// app.js also declares escapeHTML (identical logic); the function declaration there
// will simply overwrite this one at parse time â€” no conflict.
function escapeHTML(s) {
  return String(s).replace(/&/g,'&amp;').replace(/</g,'&lt;').replace(/>/g,'&gt;').replace(/"/g,'&quot;');
}

