// â”€â”€ Locality habitat context (supplements genus text) â”€â”€
const LOCALITY_CONTEXT = {
  'Lake Malawi':   'a Rift Valley lake in East Africa â€” the world\'s ninth-largest, 560 km long, and home to approximately 1,000 species of cichlid fish, more than any comparable freshwater body on Earth',
  'Lake Tanganyika':'the world\'s second-deepest lake and oldest of the African Great Rift Valley lakes; at 673 m deep it has an oxic zone only in the top 200 m; its extraordinary age (9â€“12 million years) allowed cichlids to diversify into 250+ endemic species',
  'Lake Victoria': 'the world\'s largest tropical lake and second-largest freshwater lake by area; home to the most rapid vertebrate radiation in evolutionary history; the introduction of Nile perch in the 1950s caused 200+ cichlid extinctions',
  'Red Sea':       'arguably the world\'s most fish-rich body of water per unit area; an enclosed sea connected to the Indian Ocean by the narrow Bab-el-Mandeb Strait; its enclosed geography led to the evolution of many endemic species; water temperatures regularly exceed 30Â°C',
  'Amazon River':  'the world\'s largest river by discharge volume, draining 40% of South America; its blackwater and clearwater tributaries host over 3,000 species of freshwater fish, the most diverse freshwater fish fauna on Earth',
  'Orinoco':       'the Orinoco River basin of Venezuela and Colombia, sharing many species with the Amazon but with significant unique endemism in its headwaters; seasonally flooded llanos are critical habitat for many species',
  'Raja Ampat':    'an archipelago in West Papua, Indonesia, considered the global center of marine biodiversity; contains more reef fish species per square meter than any other documented site on Earth',
  'Coral Triangle': 'a marine region encompassing the Philippines, Indonesia, Malaysia, Papua New Guinea, Solomon Islands, and Timor-Leste â€” the center of marine biodiversity, with 600+ coral species and 2,000+ reef fish species',
};

// â”€â”€ Build a rich contextual bio from genus knowledge + fish data â”€â”€
function buildFallbackBio(f) {
  const g   = GENUS_ECOLOGY[f.genus] || {};
  const loc = f.locality || '';
  const statusCode = f.status || '?';
  const statusName = (typeof STATUS_NAMES !== 'undefined' ? STATUS_NAMES[statusCode] : null) || statusCode;
  const genusCount = (typeof FISH_DATA !== 'undefined') ? FISH_DATA.filter(x => x.genus === f.genus).length : 0;
  const locCount   = (typeof FISH_DATA !== 'undefined' && loc) ? FISH_DATA.filter(x => x.locality === loc).length : 0;

  const parts = [];

  // Opening: species identity
  if (f.genus && f.species && f.species !== '') {
    const speciesEtym = buildSpeciesNote(f.species);
    parts.push(`<p class="detail-prose"><em>${f.genus} ${f.species}</em>${f.name ? ' â€” commonly known as the <strong>' + escapeHTML(f.name) + '</strong>' : ''} â€” is a member of the family <strong>${g.fam || 'Teleostei'}</strong>${g.type ? ', specifically a ' + g.type : ''}.${speciesEtym ? ' ' + speciesEtym : ''}</p>`);
  }

  // Habitat + ecology
  if (g.habitat) {
    let habitatText = `<p class="detail-prose">This species inhabits ${g.habitat}.`;
    if (g.depth) habitatText += ` Typical depth range is ${g.depth}.`;
    if (loc) {
      // Add locality context if we know something about it
      const locKey = Object.keys(LOCALITY_CONTEXT).find(k => loc.toLowerCase().includes(k.toLowerCase()));
      if (locKey) habitatText += ` Its locality of <strong>${escapeHTML(loc)}</strong> is within ${LOCALITY_CONTEXT[locKey]}.`;
      else habitatText += ` The recorded locality for this individual is <strong>${escapeHTML(loc)}</strong>.`;
    }
    habitatText += '</p>';
    parts.push(habitatText);
  } else if (loc) {
    parts.push(`<p class="detail-prose">This specimen was recorded from <strong>${escapeHTML(loc)}</strong>.${locCount > 1 ? ` A total of ${locCount} CryptoFish in the collection originate from this locality.` : ''}</p>`);
  }

  // Feeding + behavior
  if (g.feeding) {
    parts.push(`<p class="detail-prose">Feeding ecology: ${g.feeding}.</p>`);
  }
  if (g.behavior) {
    parts.push(`<p class="detail-prose">${g.behavior}.</p>`);
  }

  // Genus context
  if (genusCount > 1 && f.genus) {
    parts.push(`<p class="detail-prose bio-genus-note">The genus <em>${escapeHTML(f.genus)}</em> is represented by <strong>${genusCount} tokens</strong> in the CryptoFish collection, reflecting the extraordinary species diversity within this group.${g.notes ? ' ' + g.notes + '.' : ''}</p>`);
  } else if (g.notes) {
    parts.push(`<p class="detail-prose bio-genus-note">${g.notes}.</p>`);
  }

  // If we have nothing meaningful, give a basic note
  if (parts.length === 0) {
    parts.push(`<p class="detail-prose"><em>${escapeHTML(f.sci || f.name)}</em> â€” each token in the CryptoFish collection represents a real species researched and illustrated by Findurnemo using scientific databases including FishBase and the IUCN Red List.</p>`);
  }

  return parts.join('');
}

function buildSpeciesNote(species) {
  // Try to derive meaning from species epithet - Latin/Greek descriptors
  const notes = {
    'volitans':    'The species epithet <em>volitans</em> means "flying" in Latin, referring to the sweeping pectoral fins.',
    'aurantiacus': 'The epithet <em>aurantiacus</em> is Latin for "orange-colored."',
    'nigricans':   'The epithet <em>nigricans</em> means "becoming black" or "darkening" in Latin.',
    'bicolor':     'The epithet <em>bicolor</em> means "two-colored" in Latin.',
    'tricolor':    'The epithet <em>tricolor</em> means "three-colored" in Latin.',
    'lineatus':    'The epithet <em>lineatus</em> means "lined" or "striped" in Latin.',
    'fasciatus':   'The epithet <em>fasciatus</em> means "banded" or "striped" in Latin.',
    'maculatus':   'The epithet <em>maculatus</em> means "spotted" in Latin.',
    'zebra':       'The epithet <em>zebra</em> references the strongly banded striped pattern.',
    'moorii':      'The species was named in honor of naturalist John Moore, who collected specimens on early Lake Tanganyika expeditions.',
    'frontosa':    'The epithet <em>frontosa</em> means "having a large forehead" in Latin, referring to the nuchal hump.',
    'pulcher':     'The epithet <em>pulcher</em> is Latin for "beautiful."',
    'compressiceps': 'The epithet <em>compressiceps</em> means "compressed head" in Latin, describing the laterally-flattened body.',
    'coeruleus':   'The epithet <em>coeruleus</em> is Latin for "sky blue" or "deep blue."',
    'magnificus':  'The epithet <em>magnificus</em> is Latin for "magnificent" or "splendid."',
    'ocellatus':   'The epithet <em>ocellatus</em> means "bearing eye-spots" in Latin.',
    'hepatus':     'The epithet <em>hepatus</em> means "liver-colored" in Greek, referring to the brown body.',
    'auratus':     'The epithet <em>auratus</em> means "gilded" or "golden" in Latin.',
  };
  const key = Object.keys(notes).find(k => species.toLowerCase().includes(k));
  return key ? notes[key] : '';
}

// â”€â”€ Build honorary bio HTML â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€â”€
function buildHonoraryBio(handle) {
  const bio = HONORARY_BIOS[handle];
  if (bio) {
    return `<p class="detail-prose">${escapeHTML(bio)}</p>
    <p class="detail-prose bio-genus-note">Honorary tokens are hand-issued directly by Findurnemo as personal acknowledgments. They are not part of the open minting process and cannot be replicated â€” each one is genuinely unique in the collection.</p>`;
  }
  return `<p class="detail-prose">This is a personal honorary token created by Findurnemo for <strong>${escapeHTML(handle)}</strong>, in recognition of their contribution to the CryptoFish community.</p>
    <p class="detail-prose bio-genus-note">Honorary tokens are hand-issued directly by Findurnemo and are completely unique. They do not follow the standard species classification system â€” they are personal tributes.</p>`;
}

// â”€â”€ Main entry: fetch bio for a fish object â”€â”€â”€â”€â”€â”€â”€â”€
async function fetchFishBio(f) {
  // Pure honorary (no genus/species)
  if (f.honorary && !f.genus) {
    return { html: buildHonoraryBio(f.honorary), wiki: null };
  }

  const cacheKey = f.sci || f.name;
  if (_bioCache.has(cacheKey)) return _bioCache.get(cacheKey);

  let result = null;

  // Try Wikipedia REST API (CORS-enabled, no key needed)
  if (f.genus && f.species && f.species.trim() !== '') {
    try {
      const speciesSlug = encodeURIComponent((f.genus + '_' + f.species).replace(/ /g, '_'));
      const r = await fetch(
        `https://en.wikipedia.org/api/rest_v1/page/summary/${speciesSlug}`,
        { cache: 'force-cache', signal: AbortSignal.timeout(5000) }
      );
      if (r.ok) {
        const d = await r.json();
        if (d.type === 'standard' && d.extract && d.extract.length > 120) {
          // Split into paragraphs if the extract has multiple natural paragraphs
          const paragraphs = d.extract.split('\n').filter(p => p.trim().length > 40);
          const html = paragraphs.map(p => `<p class="detail-prose">${escapeHTML(p)}</p>`).join('') +
            (d.content_urls?.desktop?.page
              ? `<a class="wiki-link" href="${d.content_urls.desktop.page}" target="_blank" rel="noopener noreferrer">Read full article on Wikipedia â† - </a>`
              : '');
          result = { html, wiki: d.content_urls?.desktop?.page || null };
        }
      }
    } catch (_) { /* timeout or network error â€” fall through to fallback */ }
  }

  // Fall back to rich genus-based bio
  if (!result) {
    result = { html: buildFallbackBio(f), wiki: null };
  }

  _bioCache.set(cacheKey, result);
  return result;
}

